insert into public.product_detail_content (
  product_id,
  slug,
  eyebrow,
  summary,
  meta,
  overview,
  itinerary,
  includes,
  excludes,
  recommendations,
  considerations,
  cancellation_policies,
  booking_config,
  updated_by_user_id
)
values
  (
    '0e42c64f-b8db-53d6-81c8-411996810811',
    'taller-cacao-caminata-minca',
    'Experiencia recomendada',
    'Una salida de naturaleza en Minca que combina caminata suave por senderos locales con un taller artesanal de cacao. Es una experiencia pensada para conocer el entorno, entender parte del proceso del cacao y vivir una jornada relajada en la Sierra Nevada.',
    '[{"id":"PDTM-001","label":"Duracion","value":"Dia completo"},{"id":"PDTM-002","label":"Punto de encuentro","value":"Parque principal de Minca"},{"id":"PDTM-003","label":"Hora de salida","value":"7:00 a. m."},{"id":"PDTM-004","label":"Hora de regreso","value":"1:30 p. m."},{"id":"PDTM-005","label":"Recorrido","value":"Sendero local + taller de cacao"}]'::jsonb,
    '["La experiencia inicia en Minca con encuentro en punto acordado y una introduccion al recorrido del dia. Desde ahi comienza una caminata guiada por senderos de baja exigencia, pensada para disfrutar el paisaje, el clima de montana y la vegetacion del entorno.","Luego el recorrido conecta con un espacio de cacao artesanal donde se comparte una explicacion general del proceso, desde la materia prima hasta la preparacion final. Dependiendo de la operacion del dia, puede incluir degustacion, demostraciones practicas y tiempo libre para fotos o compras locales."]'::jsonb,
    '[{"id":"PDTIT-001","day":"Parada 1","title":"Encuentro y salida por sendero local","description":"Recepcion del grupo en Minca, indicaciones generales y comienzo del recorrido por sendero suave hacia la zona de experiencia."},{"id":"PDTIT-002","day":"Parada 2","title":"Interpretacion del entorno y descanso","description":"Pausa durante la caminata para apreciar el paisaje, tomar fotos y recibir contexto del territorio y sus actividades."},{"id":"PDTIT-003","day":"Parada 3","title":"Taller de cacao y cierre de la experiencia","description":"Ingreso al espacio artesanal de cacao, explicacion del proceso y cierre del recorrido segun el horario del dia."}]'::jsonb,
    '[{"id":"PDTI-001","day":"","title":"Caminata guiada en entorno natural","description":"Recorrido por senderos de baja exigencia con acompanamiento basico y lectura general del paisaje local."},{"id":"PDTI-002","day":"","title":"Taller artesanal de cacao","description":"Espacio para conocer el proceso del cacao, su preparacion y algunos elementos culturales del producto en la region."},{"id":"PDTI-003","day":"","title":"Degustacion o muestra del proceso","description":"Dependiendo de la operacion, se incluye una muestra relacionada con el cacao y su transformacion artesanal."},{"id":"PDTI-004","day":"","title":"Acompanamiento de operacion","description":"Orientacion general durante el recorrido, horarios y puntos clave de la experiencia."}]'::jsonb,
    '[{"id":"PDTE-001","day":"","title":"Transporte hasta Minca","description":"El traslado desde Santa Marta u otras ciudades puede manejarse aparte si el operador no lo incluye en esta salida."},{"id":"PDTE-002","day":"","title":"Alimentacion completa","description":"Snacks, bebidas y almuerzo dependen del plan contratado y pueden tener costo adicional."},{"id":"PDTE-003","day":"","title":"Compras personales","description":"Productos de cacao, recuerdos, fotografias o consumos extra no hacen parte del valor base."},{"id":"PDTE-004","day":"","title":"Servicios no descritos","description":"Cualquier servicio adicional ofrecido en destino queda sujeto a disponibilidad y pago directo."}]'::jsonb,
    '["Usa ropa fresca y comoda para caminar en clima de montana.","Lleva hidratacion personal y protector solar.","Prefiere tenis o calzado con buen agarre para sendero.","Carga efectivo para compras locales o consumos adicionales.","Lleva impermeable ligero si el clima cambia durante la salida.","Consulta con anticipacion el punto exacto de encuentro en Minca."]'::jsonb,
